#!/usr/bin/env python3

import os
import shlex
import shutil
import subprocess
import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parent
DIST_DIR = ROOT / "dist"


def run(cmd, cwd=ROOT):
    if isinstance(cmd, str):
        cmd_display = cmd
        shell = True
    else:
        cmd_display = " ".join(shlex.quote(str(x)) for x in cmd)
        shell = False

    print(f"> {cmd_display}", flush=True)
    result = subprocess.run(cmd, cwd=cwd, shell=shell)
    if result.returncode != 0:
        sys.exit(result.returncode)


def python_cmd():
    return [sys.executable]


def install_dependencies():
    req_file = ROOT / "requirements.txt"
    if not req_file.exists():
        print("requirements.txt not found", file=sys.stderr)
        sys.exit(1)
    run(python_cmd() + ["-m", "pip", "install", "--upgrade", "pip"])
    run(python_cmd() + ["-m", "pip", "install", "-r", str(req_file)])


def run_tests():
    pytest_ini = ROOT / "pytest.ini"
    tests_dir = ROOT / "tests"
    if pytest_ini.exists() or tests_dir.exists():
        run(python_cmd() + ["-m", "pytest", "-q"])
    else:
        print("No tests found, skipping")


def clean_dist():
    if DIST_DIR.exists():
        shutil.rmtree(DIST_DIR)
    DIST_DIR.mkdir(parents=True, exist_ok=True)


def package_app():
    clean_dist()

    pyproject = ROOT / "pyproject.toml"
    setup_py = ROOT / "setup.py"

    if pyproject.exists() or setup_py.exists():
        run(python_cmd() + ["-m", "pip", "install", "build"])
        run(python_cmd() + ["-m", "build", "--outdir", str(DIST_DIR)])
        return

    archive_base = DIST_DIR / "deployment"
    shutil.make_archive(str(archive_base), "zip", root_dir=ROOT)
    print(f"Created package: {archive_base}.zip")


def main():
    install_dependencies()
    run_tests()
    package_app()
    print("Deployment workflow completed successfully")


if __name__ == "__main__":
    main()